svg.script:
// --- COMPREHENSIVE RAG DATASET ---
const _chunks = [
  {s:"EXPERIENCE: RAMSOFT", t:"At RAMSOFT (June-Dec 2025), Naresh was an AI/LLM Intern. He architected Claude agents for Cypress-to-Playwright migration (30-40% effort reduction). Fine-tuned Whisper for medical ASR, designed sub-1.2s E2E inference pipelines, and built Python data ingestion with SonarQube quality checks."},
  {s:"EXPERIENCE: GENPACT", t:"At GENPACT (Feb-July 2024), Naresh worked as a GenAI Intern. He designed RAG systems using LangChain, embedding models, and vector search. Implemented LLM orchestration (OpenAI/Mistral), tool augmentation, and semantic search for document understanding."},
  {s:"PROJECT: TRUELARGE-RT", t:"TrueLarge-RT: Systems research for 32B-70B parameter LLM inference on Android. Uses GGUF, mmap, and layer-streaming to bypass RAM limits on edge devices (Kotlin, C++, Quantization)."},
  {s:"PROJECT: EDGEMIND", t:"EdgeMind: Fully on-device Agentic RAG assistant for Android. Features natural language control for system actions (Bluetooth, Settings, Settings) and local LLM execution for 100% privacy (Kotlin, HuggingFace)."},
  {s:"PROJECT: INSIGHTFUSION", t:"Multimodal InsightFusion: Vision-Language RAG system integrating OpenCLIP embeddings with Mistral LLM for semantic image-to-text similarity search and contextual response generation."},
  {s:"TECHNICAL EXPERTISE", t:"Naresh's core skills include Generative AI (RAG, LLMs, Fine-Tuning, Prompt Eng), Engineering (Quantization, GGUF, Semantic Search, Vector DBs), Programming (Python, C++, Kotlin, Java, SQL), and Tools (LangChain, HuggingFace, Docker, SonarQube)."},
  {s:"EDUCATION & SUCCESS", t:"BE in Information Science from BMS College of Engineering (2025) with 7.7 CGPA. Research published on arXiv (2401.13613) regarding CLI P-based image retrieval. Certified by IBM and Udemy."}
];

const _sw = {"me":1,"my":1,"about":1,"tell":1,"the":1,"is":1,"and":1,"to":1,"of":1,"in":1,"with":1,"for":1,"on":1,"by":1,"as":1,"at":1,"it":1};
let _vocab = {}, _idf = [], _vecs = [];

function initRAG() {
  const df = {};
  _chunks.forEach(c => {
    const tokens = tokenize(c.t);
    [...new Set(tokens)].forEach(t => df[t] = (df[t] || 0) + 1);
  });
  const v = Object.keys(df);
  v.forEach((w, i) => _vocab[w] = i);
  const n = _chunks.length;
  _idf = v.map(w => Math.log(n / (1 + df[w])) + 1);
  _chunks.forEach(c => {
    const tf = {};
    tokenize(c.t).forEach(t => tf[_vocab[t]] = (tf[_vocab[t]] || 0) + 1);
    let normSq = 0, vec = [];
    for (let idx in tf) {
      let w = tf[idx] * _idf[idx];
      vec.push([parseInt(idx), w]);
      normSq += w * w;
    }
    let nrm = Math.sqrt(normSq) || 1;
    _vecs.push(vec.map(p => [p[0], p[1] / nrm]));
  });
}

function tokenize(s) { 
  return s.toLowerCase()
          .replace(/experience|exp|work|intern|role/g, "experience")
          .replace(/projects?|research|built|made/g, "project")
          .match(/[a-z0-9]+/g)
          .filter(t => t.length > 1 && !_sw[t]); 
}

function cosine(qv, dv) {
  let dot = 0;
  dv.forEach(p => { if (qv[p[0]]) dot += qv[p[0]] * p[1]; });
  return dot;
}

function getContext(q) {
  const tokens = tokenize(q);
  const tf = {};
  tokens.forEach(t => { if (_vocab[t] !== undefined) tf[_vocab[t]] = (tf[_vocab[t]] || 0) + 1; });
  let qv = {}, normSq = 0;
  for (let idx in tf) {
    let w = tf[idx] * _idf[idx];
    qv[idx] = w;
    normSq += w * w;
  }
  let nrm = Math.sqrt(normSq) || 1;
  for (let k in qv) qv[k] /= nrm;

  const scores = _vecs.map((dv, i) => [i, cosine(qv, dv)]);
  scores.sort((a,b) => b[1] - a[1]);

  const top = scores.slice(0, 3).filter(s => s[1] > 0.05 || s === scores[0]);
  return { 
    text: top.map(s => _chunks[s[0]].t).join("\n\n"),
    debug: top.map(s => `[${_chunks[s[0]].s}] Match: ${(s[1]*100).toFixed(1)}%`).join("\n")
  };
}

function renderMarkdown(md) {
  if (!md) return "";
  return md
    .replace(/^### (.*$)/gim, '<strong style="color:#0f172a; display:block; margin-top:10px;">$1</strong>')
    .replace(/^## (.*$)/gim, '<strong style="color:#0f172a; display:block; margin-top:10px;">$1</strong>')
    .replace(/^# (.*$)/gim, '<strong style="color:#0f172a; display:block; margin-top:20px; font-size:1.1em;">$1</strong>')
    .replace(/\*\*(.*)\*\*/gim, '<strong>$1</strong>')
    .replace(/\*(.*)\*/gim, '<em>$1</em>')
    .replace(/^\* (.*$)/gim, '<div style="margin-left:10px;">• $1</div>')
    .replace(/^- (.*$)/gim, '<div style="margin-left:10px;">• $1</div>')
    .replace(/\n\n/g, '<div style="height:10px;"></div>')
    .replace(/\n/g, '<br/>');
}

async function handleChat() {
  const input = document.getElementById('userInput');
  const q = input.value;
  if (!q.trim()) return;

  const status = document.getElementById('status');
  const resPanel = document.getElementById('aiResponse');
  const resText = document.getElementById('responseText');
  const dbg = document.getElementById('debugging');
  const chunksArea = document.getElementById('chunksArea');

  status.innerHTML = '<span class="loading-dots" style="color:#3b82f6; font-weight:600;">Generating Insights</span>';

  const ctx = getContext(q);
  chunksArea.innerText = ctx.debug + "\n\nRetrieved Context:\n" + ctx.text;
  dbg.style.display = "block";

  try {
    const response = await fetch('http://localhost:3000/generate-rag-json', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ prompt: q, context: ctx.text })
    });

    const data = await response.json();
    if (data.reply) {
      resText.innerHTML = renderMarkdown(data.reply);
      resPanel.style.display = "block";
      status.innerText = "Response Ready.";
      input.value = "";
    } else {
      throw new Error(data.error || "Deep Intelligence unavailable");
    }
  } catch (e) {
    status.innerText = "Signal Loss.";
    resText.innerHTML = '<div style="color:#ef4444;"><strong>Error:</strong> ' + e.message + "</div>";
    resPanel.style.display = "block";
  }
}

initRAG();
